import { createSlice, nanoid } from "@reduxjs/toolkit";

const initialState = {
  items: [],
};

const shoppingListSlice = createSlice({
  name: "shoppingList",
  initialState,
  reducers: {
    addShoppingItems: {
      reducer(state, action) {
        action.payload.forEach((item) => {
          const name = typeof item === "string" ? item : item.name;
          const exists = state.items.some((current) => current.name.toLowerCase() === name.toLowerCase());

          if (!exists) {
            state.items.push({ id: nanoid(), name, checked: false });
          }
        });
      },
      prepare(items) {
        return { payload: Array.isArray(items) ? items : [] };
      },
    },
    toggleShoppingItem(state, action) {
      const item = state.items.find((current) => current.id === action.payload);
      if (item) item.checked = !item.checked;
    },
    removeShoppingItem(state, action) {
      state.items = state.items.filter((item) => item.id !== action.payload);
    },
  },
});

export const { addShoppingItems, toggleShoppingItem, removeShoppingItem } = shoppingListSlice.actions;
export default shoppingListSlice.reducer;
